         where DTO : BaseDataTransferObject, new()
         where M : CatsDbModel, new()
     {
-        var rtn = new List<M>();
         Expression<Func<M, bool>> fullExpression = null;
         foreach (var filter in filters)
         {
             if (filter == null) continue;
             fullExpression = fullExpression == null ? filter : fullExpression.ComposeAnd(filter);
         }
-        var set = db.Set<M>();
-        return fullExpression == null ? set.ToList() : set.Where(fullExpression).ToList();
+
+        var query = db.Set<M>().AsNoTracking().AsQueryable();
+        if (fullExpression != null)
+        {
+            query = query.Where(fullExpression);
+        }
+
+        var skip = rpt?.query?.skip ?? 0;
+        if (skip > 0)
+        {
+            query = query.Skip(skip);
+        }
+
+        // CCQuery defaults take to 1000; honor that contract here instead of loading full tables.
+        var take = rpt?.query?.take ?? 1000;
+        if (take > 0)
+        {
+            query = query.Take(take);
+        }
+
+        return query.ToList();
     }


